<template><section class="page"><el-alert v-if="error" type="error" :title="error" show-icon/><div class="grid" v-loading="loading"><div class="metric" v-for="m in metrics" :key="m.label"><span>{{m.label}}</span><br><b>{{m.value}}</b></div></div><div class="panel"><h3>最近事件</h3><el-table :data="data.recentEvents || []"><el-table-column prop="tracking_no" label="运单号"/><el-table-column prop="normalized_status" label="状态"><template #default="s"><el-tag :type="statusType(s.row.normalized_status)">{{statusText[s.row.normalized_status]}}</el-tag></template></el-table-column><el-table-column prop="event_time" label="发生时间"><template #default="s">{{formatTime(s.row.event_time)}}</template></el-table-column><el-table-column prop="source" label="来源"/></el-table></div></section></template>
<script setup lang="ts">import { computed, onMounted, ref } from 'vue'; import { http } from '../api/http'; import { formatTime,statusText,statusType } from '../utils/status'; const data=ref<any>({}); const loading=ref(false); const error=ref(''); const metrics=computed(()=>[{label:'运单总数',value:data.value.shipmentTotal??0},{label:'运输中',value:data.value.inTransit??0},{label:'已签收',value:data.value.delivered??0},{label:'异常运单',value:data.value.openAnomalies??0},{label:'今日事件',value:data.value.todayEvents??0},{label:'今日对账差异',value:data.value.todayDifferences??0}]); async function load(){loading.value=true;error.value='';try{data.value=await http.get('/dashboard')}catch(e:any){error.value=e.message}finally{loading.value=false}} onMounted(load)</script>
